package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void testSetDateFormat_ReturnsThisAndSetsDatePattern() throws Exception {
    String pattern = "yyyy-MM-dd";

    GsonBuilder returned = gsonBuilder.setDateFormat(pattern);

    assertSame(gsonBuilder, returned, "setDateFormat should return this");
    // Use reflection to verify private field datePattern is set
    Field datePatternField = GsonBuilder.class.getDeclaredField("datePattern");
    datePatternField.setAccessible(true);
    String actualPattern = (String) datePatternField.get(gsonBuilder);
    assertEquals(pattern, actualPattern, "datePattern field should be set to the given pattern");
  }
}
